import { useCallback, useState } from '@wordpress/element';
import { __ } from '@wordpress/i18n';
// @ts-ignore — package-style alias resolved by Pro webpack.
import { DokanButton } from '@dokan/components';
import {
    Plus,
    Trash2,
    ChevronDown,
    ChevronUp,
    Download,
    Upload,
} from 'lucide-react';

import {
    AddonOption,
    AddonOptionPriceType,
    AddonPriceType,
    AddonRestriction,
    AddonTitleFormat,
    AddonType,
    ProductAddon,
} from './types';

interface EditProps {
    data: Record< string, any >;
    field: { id: string; label?: string };
    onChange: ( changes: Record< string, any > ) => void;
}

declare const dokanProductEditorAddon:
    | { globalAddonsUrl?: string }
    | undefined;

const ADDON_TYPES: { value: AddonType; label: string }[] = [
    { value: 'multiple_choice', label: __( 'Multiple Choice', 'dokan' ) },
    { value: 'checkbox', label: __( 'Checkbox', 'dokan' ) },
    { value: 'custom_text', label: __( 'Short Text', 'dokan' ) },
    { value: 'custom_textarea', label: __( 'Long Text', 'dokan' ) },
    { value: 'file_upload', label: __( 'File Upload', 'dokan' ) },
    { value: 'custom_price', label: __( 'Price', 'dokan' ) },
    { value: 'input_multiplier', label: __( 'Quantity', 'dokan' ) },
    { value: 'heading', label: __( 'Heading', 'dokan' ) },
];

const TITLE_FORMATS: { value: AddonTitleFormat; label: string }[] = [
    { value: 'label', label: __( 'Label', 'dokan' ) },
    { value: 'heading', label: __( 'Heading', 'dokan' ) },
    { value: 'hide', label: __( 'Hide', 'dokan' ) },
];

const DISPLAY_FORMATS = [
    { value: 'select', label: __( 'Drop Down', 'dokan' ) },
    { value: 'radiobutton', label: __( 'Radio Buttons', 'dokan' ) },
    { value: 'images', label: __( 'Images', 'dokan' ) },
];

const RESTRICTION_TYPES: { value: AddonRestriction; label: string }[] = [
    { value: 'any_text', label: __( 'Any text', 'dokan' ) },
    { value: 'only_letters', label: __( 'Only letters', 'dokan' ) },
    { value: 'only_numbers', label: __( 'Only numbers', 'dokan' ) },
    { value: 'only_letters_numbers', label: __( 'Only letters & numbers', 'dokan' ) },
    { value: 'email', label: __( 'Email', 'dokan' ) },
];

const PRICE_TYPES: { value: AddonPriceType; label: string }[] = [
    { value: 'flat_fee', label: __( 'Flat fee', 'dokan' ) },
    { value: 'quantity_based', label: __( 'Quantity based', 'dokan' ) },
    { value: 'percentage_based', label: __( 'Percentage based', 'dokan' ) },
];

const OPTION_PRICE_TYPES: { value: AddonOptionPriceType; label: string }[] = [
    { value: 'flat_fee', label: __( 'Flat fee', 'dokan' ) },
    { value: 'percentage_based', label: __( 'Percentage based', 'dokan' ) },
];

const HAS_OPTIONS: AddonType[] = [ 'multiple_choice', 'checkbox' ];
const SUPPORTS_PRICE_ADJUST: AddonType[] = [ 'custom_text', 'custom_textarea', 'custom_price', 'input_multiplier', 'file_upload' ];
const HAS_TEXT_RESTRICTIONS: AddonType[] = [ 'custom_text', 'custom_textarea' ];
const HAS_NUMERIC_RANGE: AddonType[] = [ 'custom_price', 'input_multiplier' ];

const inputCls =
    'w-full rounded border border-gray-300 px-3 py-2 text-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500';
const labelCls = 'block text-sm font-medium text-gray-700 mb-1';

const randomId = (): string =>
    Math.random().toString( 36 ).slice( 2, 10 );

const blankOption = (): AddonOption => ( {
    label: '',
    price: '',
    image: '',
    price_type: 'flat_fee',
} );

const blankAddon = ( position: number ): ProductAddon => ( {
    id: randomId(),
    name: '',
    title_format: 'label',
    description_enable: 0,
    description: '',
    type: 'multiple_choice',
    display: 'select',
    position,
    required: 0,
    restrictions: 0,
    restrictions_type: 'any_text',
    adjust_price: 0,
    price_type: 'flat_fee',
    price: '',
    min: 0,
    max: 0,
    options: [ blankOption() ],
} );

const ProductAddonsEdit = ( { data, field, onChange }: EditProps ) => {
    const addons: ProductAddon[] = Array.isArray( data[ field.id ] )
        ? data[ field.id ]
        : [];
    const [ expanded, setExpanded ] = useState< Record< string, boolean > >(
        {}
    );

    const update = useCallback(
        ( next: ProductAddon[] ) => {
            onChange( {
                [ field.id ]: next.map( ( addon, idx ) => ( {
                    ...addon,
                    position: idx,
                } ) ),
            } );
        },
        [ field.id, onChange ]
    );

    const updateAddon = ( index: number, patch: Partial< ProductAddon > ) => {
        const next = [ ...addons ];
        next[ index ] = { ...next[ index ], ...patch };
        update( next );
    };

    const removeAddon = ( index: number ) => {
        const next = addons.filter( ( _, i ) => i !== index );
        update( next );
    };

    const addAddon = () => {
        const fresh = blankAddon( addons.length );
        update( [ ...addons, fresh ] );
        setExpanded( ( prev ) => ( { ...prev, [ fresh.id ]: true } ) );
    };

    const toggle = ( id: string ) =>
        setExpanded( ( prev ) => ( { ...prev, [ id ]: ! prev[ id ] } ) );

    const updateOptions = ( index: number, options: AddonOption[] ) => {
        updateAddon( index, { options } );
    };

    const [ exportText, setExportText ] = useState< string | null >( null );
    const [ importText, setImportText ] = useState< string | null >( null );
    const [ importError, setImportError ] = useState< string | null >( null );

    const handleExport = () => {
        setImportText( null );
        setImportError( null );
        setExportText( JSON.stringify( addons, null, 2 ) );
    };

    const handleOpenImport = () => {
        setExportText( null );
        setImportError( null );
        setImportText( '' );
    };

    const handleApplyImport = () => {
        try {
            const parsed = JSON.parse( importText || '' );
            if ( ! Array.isArray( parsed ) ) {
                throw new Error(
                    __( 'Expected a JSON array of add-ons.', 'dokan' )
                );
            }
            // Re-id imported entries so they don't clash with existing IDs.
            const merged = [
                ...addons,
                ...parsed.map( ( a: ProductAddon ) => ( {
                    ...a,
                    id: randomId(),
                } ) ),
            ];
            update( merged );
            setImportText( null );
        } catch ( err: any ) {
            setImportError(
                err?.message || __( 'Invalid JSON', 'dokan' )
            );
        }
    };

    const globalAddonsUrl =
        ( typeof dokanProductEditorAddon !== 'undefined' &&
            dokanProductEditorAddon?.globalAddonsUrl ) ||
        '#';

    return (
        <div className="dokan-product-addons-editor space-y-3">
            { addons.length === 0 && (
                <p className="text-sm text-gray-500 italic">
                    { __(
                        'No add-on fields yet. Click “Add field” to create one.',
                        'dokan'
                    ) }
                </p>
            ) }

            { addons.map( ( addon, index ) => {
                const isOpen = !! expanded[ addon.id ];
                const typeLabel =
                    ADDON_TYPES.find( ( t ) => t.value === addon.type )
                        ?.label ?? addon.type;

                return (
                    <div
                        key={ addon.id }
                        className="rounded border border-gray-200 bg-white"
                    >
                        <div className="flex items-center justify-between px-3 py-2 bg-gray-50">
                            <button
                                type="button"
                                onClick={ () => toggle( addon.id ) }
                                className="flex items-center gap-2 text-left flex-1 cursor-pointer"
                            >
                                { isOpen ? (
                                    <ChevronUp size={ 16 } />
                                ) : (
                                    <ChevronDown size={ 16 } />
                                ) }
                                <span className="font-medium text-sm">
                                    { addon.name ||
                                        __( '(Untitled add-on)', 'dokan' ) }
                                </span>
                                <span className="text-xs text-gray-500">
                                    { typeLabel }
                                </span>
                            </button>
                            <button
                                type="button"
                                onClick={ () => removeAddon( index ) }
                                className="text-red-500 hover:text-red-700 cursor-pointer"
                                aria-label={ __( 'Remove add-on', 'dokan' ) }
                            >
                                <Trash2 size={ 16 } />
                            </button>
                        </div>

                        { isOpen && (
                            <div className="p-4 space-y-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div>
                                        <label className={ labelCls }>
                                            { __( 'Type', 'dokan' ) }
                                        </label>
                                        <select
                                            className={ inputCls }
                                            value={ addon.type }
                                            onChange={ ( e ) =>
                                                updateAddon( index, {
                                                    type: e.target
                                                        .value as AddonType,
                                                } )
                                            }
                                        >
                                            { ADDON_TYPES.map( ( opt ) => (
                                                <option
                                                    key={ opt.value }
                                                    value={ opt.value }
                                                >
                                                    { opt.label }
                                                </option>
                                            ) ) }
                                        </select>
                                    </div>

                                    <div>
                                        <label className={ labelCls }>
                                            { __( 'Title', 'dokan' ) }
                                        </label>
                                        <input
                                            className={ inputCls }
                                            type="text"
                                            value={ addon.name }
                                            onChange={ ( e ) =>
                                                updateAddon( index, {
                                                    name: e.target.value,
                                                } )
                                            }
                                            placeholder={ __(
                                                'Add a label',
                                                'dokan'
                                            ) }
                                        />
                                    </div>

                                    <div>
                                        <label className={ labelCls }>
                                            { __( 'Title format', 'dokan' ) }
                                        </label>
                                        <select
                                            className={ inputCls }
                                            value={ addon.title_format }
                                            onChange={ ( e ) =>
                                                updateAddon( index, {
                                                    title_format: e.target
                                                        .value as AddonTitleFormat,
                                                } )
                                            }
                                        >
                                            { TITLE_FORMATS.map( ( opt ) => (
                                                <option
                                                    key={ opt.value }
                                                    value={ opt.value }
                                                >
                                                    { opt.label }
                                                </option>
                                            ) ) }
                                        </select>
                                    </div>

                                    { 'multiple_choice' === addon.type && (
                                        <div>
                                            <label className={ labelCls }>
                                                { __(
                                                    'Display format',
                                                    'dokan'
                                                ) }
                                            </label>
                                            <select
                                                className={ inputCls }
                                                value={ addon.display }
                                                onChange={ ( e ) =>
                                                    updateAddon( index, {
                                                        display: e.target
                                                            .value as ProductAddon[ 'display' ],
                                                    } )
                                                }
                                            >
                                                { DISPLAY_FORMATS.map(
                                                    ( opt ) => (
                                                        <option
                                                            key={ opt.value }
                                                            value={ opt.value }
                                                        >
                                                            { opt.label }
                                                        </option>
                                                    )
                                                ) }
                                            </select>
                                        </div>
                                    ) }
                                </div>

                                <div>
                                    <label className="flex items-center gap-2 text-sm">
                                        <input
                                            type="checkbox"
                                            checked={
                                                !! addon.description_enable
                                            }
                                            onChange={ ( e ) =>
                                                updateAddon( index, {
                                                    description_enable: e
                                                        .target.checked
                                                        ? 1
                                                        : 0,
                                                } )
                                            }
                                        />
                                        { __( 'Add description', 'dokan' ) }
                                    </label>
                                    { !! addon.description_enable && (
                                        <textarea
                                            className={ `${ inputCls } mt-2` }
                                            rows={ 2 }
                                            value={ addon.description }
                                            onChange={ ( e ) =>
                                                updateAddon( index, {
                                                    description:
                                                        e.target.value,
                                                } )
                                            }
                                        />
                                    ) }
                                </div>

                                { 'heading' !== addon.type && (
                                    <label className="flex items-center gap-2 text-sm">
                                        <input
                                            type="checkbox"
                                            checked={ !! addon.required }
                                            onChange={ ( e ) =>
                                                updateAddon( index, {
                                                    required: e.target
                                                        .checked
                                                        ? 1
                                                        : 0,
                                                } )
                                            }
                                        />
                                        { __(
                                            'Required field',
                                            'dokan'
                                        ) }
                                    </label>
                                ) }

                                { HAS_OPTIONS.includes( addon.type ) && (
                                    <OptionsEditor
                                        options={ addon.options || [] }
                                        onChange={ ( opts ) =>
                                            updateOptions( index, opts )
                                        }
                                    />
                                ) }

                                { HAS_TEXT_RESTRICTIONS.includes(
                                    addon.type
                                ) && (
                                    <TextRestrictions
                                        addon={ addon }
                                        onChange={ ( patch ) =>
                                            updateAddon( index, patch )
                                        }
                                    />
                                ) }

                                { SUPPORTS_PRICE_ADJUST.includes(
                                    addon.type
                                ) &&
                                    ! HAS_OPTIONS.includes( addon.type ) && (
                                        <PriceAdjustment
                                            addon={ addon }
                                            onChange={ ( patch ) =>
                                                updateAddon( index, patch )
                                            }
                                            showRange={ HAS_NUMERIC_RANGE.includes(
                                                addon.type
                                            ) }
                                        />
                                    ) }
                            </div>
                        ) }
                    </div>
                );
            } ) }

            <div className="flex items-center justify-between flex-wrap gap-2 pt-2">
                <DokanButton
                    type="button"
                    variant="secondary"
                    onClick={ addAddon }
                    className="flex items-center gap-1"
                >
                    <Plus size={ 14 } />
                    { __( 'Add field', 'dokan' ) }
                </DokanButton>
                <div className="flex items-center gap-2">
                    <DokanButton
                        type="button"
                        variant="secondary"
                        onClick={ handleOpenImport }
                        className="flex items-center gap-1"
                    >
                        <Upload size={ 14 } />
                        { __( 'Import', 'dokan' ) }
                    </DokanButton>
                    <DokanButton
                        type="button"
                        variant="secondary"
                        onClick={ handleExport }
                        className="flex items-center gap-1"
                    >
                        <Download size={ 14 } />
                        { __( 'Export', 'dokan' ) }
                    </DokanButton>
                </div>
            </div>

            { exportText !== null && (
                <div className="border rounded p-3 space-y-2">
                    <div className="text-sm font-medium">
                        { __( 'Export (copy this JSON):', 'dokan' ) }
                    </div>
                    <textarea
                        readOnly
                        className={ `${ inputCls } font-mono text-xs` }
                        rows={ 6 }
                        value={ exportText }
                        onFocus={ ( e ) => e.currentTarget.select() }
                    />
                    <button
                        type="button"
                        className="text-sm text-gray-500 hover:underline cursor-pointer"
                        onClick={ () => setExportText( null ) }
                    >
                        { __( 'Close', 'dokan' ) }
                    </button>
                </div>
            ) }

            { importText !== null && (
                <div className="border rounded p-3 space-y-2">
                    <div className="text-sm font-medium">
                        { __( 'Import (paste JSON array):', 'dokan' ) }
                    </div>
                    <textarea
                        className={ `${ inputCls } font-mono text-xs` }
                        rows={ 6 }
                        value={ importText }
                        onChange={ ( e ) => {
                            setImportText( e.target.value );
                            setImportError( null );
                        } }
                    />
                    { importError && (
                        <p className="text-xs text-red-600">
                            { importError }
                        </p>
                    ) }
                    <div className="flex gap-2">
                        <DokanButton
                            type="button"
                            variant="primary"
                            onClick={ handleApplyImport }
                        >
                            { __( 'Import', 'dokan' ) }
                        </DokanButton>
                        <button
                            type="button"
                            className="text-sm text-gray-500 hover:underline cursor-pointer"
                            onClick={ () => setImportText( null ) }
                        >
                            { __( 'Cancel', 'dokan' ) }
                        </button>
                    </div>
                </div>
            ) }

            <div className="border-t pt-3 mt-2">
                <h4 className="text-sm font-semibold mb-1">
                    { __( 'Additional add-ons', 'dokan' ) }
                </h4>
                <p className="text-sm text-gray-600">
                    { __( 'You can create additional ', 'dokan' ) }
                    <a
                        href={ globalAddonsUrl }
                        className="text-blue-600 hover:underline"
                    >
                        { __( 'add-ons', 'dokan' ) }
                    </a>
                    { __(
                        ' that apply to all products or to certain categories.',
                        'dokan'
                    ) }
                </p>
            </div>
        </div>
    );
};

interface OptionsEditorProps {
    options: AddonOption[];
    onChange: ( options: AddonOption[] ) => void;
}

const OptionsEditor = ( { options, onChange }: OptionsEditorProps ) => {
    const update = ( index: number, patch: Partial< AddonOption > ) => {
        const next = [ ...options ];
        next[ index ] = { ...next[ index ], ...patch };
        onChange( next );
    };
    const remove = ( index: number ) =>
        onChange( options.filter( ( _, i ) => i !== index ) );
    const add = () => onChange( [ ...options, blankOption() ] );

    return (
        <div className="border-t pt-3">
            <div className="text-sm font-medium mb-2">
                { __( 'Options', 'dokan' ) }
            </div>
            <div className="space-y-2">
                { options.map( ( option, idx ) => (
                    <div
                        key={ idx }
                        className="grid grid-cols-12 gap-2 items-center"
                    >
                        <input
                            className={ `${ inputCls } col-span-4` }
                            type="text"
                            value={ option.label }
                            onChange={ ( e ) =>
                                update( idx, { label: e.target.value } )
                            }
                            placeholder={ __( 'Option label', 'dokan' ) }
                        />
                        <input
                            className={ `${ inputCls } col-span-3` }
                            type="number"
                            step="0.01"
                            value={ option.price }
                            onChange={ ( e ) =>
                                update( idx, { price: e.target.value } )
                            }
                            placeholder={ __( 'Price', 'dokan' ) }
                        />
                        <select
                            className={ `${ inputCls } col-span-3` }
                            value={ option.price_type }
                            onChange={ ( e ) =>
                                update( idx, {
                                    price_type: e.target
                                        .value as AddonOptionPriceType,
                                } )
                            }
                        >
                            { OPTION_PRICE_TYPES.map( ( opt ) => (
                                <option key={ opt.value } value={ opt.value }>
                                    { opt.label }
                                </option>
                            ) ) }
                        </select>
                        <button
                            type="button"
                            onClick={ () => remove( idx ) }
                            className="col-span-2 text-red-500 hover:text-red-700 cursor-pointer flex justify-center"
                            aria-label={ __( 'Remove option', 'dokan' ) }
                        >
                            <Trash2 size={ 14 } />
                        </button>
                        <input
                            className={ `${ inputCls } col-span-12` }
                            type="text"
                            value={ option.image }
                            onChange={ ( e ) =>
                                update( idx, { image: e.target.value } )
                            }
                            placeholder={ __(
                                'Image URL (optional, used when display = images)',
                                'dokan'
                            ) }
                        />
                    </div>
                ) ) }
            </div>
            <button
                type="button"
                onClick={ add }
                className="mt-2 text-sm text-blue-600 hover:underline cursor-pointer"
            >
                + { __( 'Add option', 'dokan' ) }
            </button>
        </div>
    );
};

interface TextRestrictionsProps {
    addon: ProductAddon;
    onChange: ( patch: Partial< ProductAddon > ) => void;
}

const TextRestrictions = ( { addon, onChange }: TextRestrictionsProps ) => (
    <div className="border-t pt-3 space-y-3">
        <label className="flex items-center gap-2 text-sm">
            <input
                type="checkbox"
                checked={ !! addon.restrictions }
                onChange={ ( e ) =>
                    onChange( { restrictions: e.target.checked ? 1 : 0 } )
                }
            />
            { __( 'Add restrictions', 'dokan' ) }
        </label>

        { !! addon.restrictions && (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                <div>
                    <label className={ labelCls }>
                        { __( 'Restriction type', 'dokan' ) }
                    </label>
                    <select
                        className={ inputCls }
                        value={ addon.restrictions_type }
                        onChange={ ( e ) =>
                            onChange( {
                                restrictions_type: e.target
                                    .value as AddonRestriction,
                            } )
                        }
                    >
                        { RESTRICTION_TYPES.map( ( opt ) => (
                            <option key={ opt.value } value={ opt.value }>
                                { opt.label }
                            </option>
                        ) ) }
                    </select>
                </div>
                <div>
                    <label className={ labelCls }>
                        { __( 'Min characters', 'dokan' ) }
                    </label>
                    <input
                        className={ inputCls }
                        type="number"
                        value={ addon.min }
                        onChange={ ( e ) =>
                            onChange( { min: Number( e.target.value ) } )
                        }
                    />
                </div>
                <div>
                    <label className={ labelCls }>
                        { __( 'Max characters', 'dokan' ) }
                    </label>
                    <input
                        className={ inputCls }
                        type="number"
                        value={ addon.max }
                        onChange={ ( e ) =>
                            onChange( { max: Number( e.target.value ) } )
                        }
                    />
                </div>
            </div>
        ) }
    </div>
);

interface PriceAdjustmentProps {
    addon: ProductAddon;
    onChange: ( patch: Partial< ProductAddon > ) => void;
    showRange: boolean;
}

const PriceAdjustment = ( {
    addon,
    onChange,
    showRange,
}: PriceAdjustmentProps ) => (
    <div className="border-t pt-3 space-y-3">
        <label className="flex items-center gap-2 text-sm">
            <input
                type="checkbox"
                checked={ !! addon.adjust_price }
                onChange={ ( e ) =>
                    onChange( { adjust_price: e.target.checked ? 1 : 0 } )
                }
            />
            { __( 'Adjust product price', 'dokan' ) }
        </label>

        { !! addon.adjust_price && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <div>
                    <label className={ labelCls }>
                        { __( 'Price type', 'dokan' ) }
                    </label>
                    <select
                        className={ inputCls }
                        value={ addon.price_type }
                        onChange={ ( e ) =>
                            onChange( {
                                price_type: e.target.value as AddonPriceType,
                            } )
                        }
                    >
                        { PRICE_TYPES.map( ( opt ) => (
                            <option key={ opt.value } value={ opt.value }>
                                { opt.label }
                            </option>
                        ) ) }
                    </select>
                </div>
                <div>
                    <label className={ labelCls }>
                        { __( 'Price', 'dokan' ) }
                    </label>
                    <input
                        className={ inputCls }
                        type="number"
                        step="0.01"
                        value={ addon.price }
                        onChange={ ( e ) =>
                            onChange( { price: e.target.value } )
                        }
                    />
                </div>
            </div>
        ) }

        { showRange && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <div>
                    <label className={ labelCls }>
                        { __( 'Minimum', 'dokan' ) }
                    </label>
                    <input
                        className={ inputCls }
                        type="number"
                        value={ addon.min }
                        onChange={ ( e ) =>
                            onChange( { min: Number( e.target.value ) } )
                        }
                    />
                </div>
                <div>
                    <label className={ labelCls }>
                        { __( 'Maximum', 'dokan' ) }
                    </label>
                    <input
                        className={ inputCls }
                        type="number"
                        value={ addon.max }
                        onChange={ ( e ) =>
                            onChange( { max: Number( e.target.value ) } )
                        }
                    />
                </div>
            </div>
        ) }
    </div>
);

export default ProductAddonsEdit;
