import domReady from '@wordpress/dom-ready';
import { addFilter } from '@wordpress/hooks';

import ProductAddonsEdit from './ProductAddonsEdit';

// Register the `product_addons` variant with the new Product Form Manager
// so vendors can manage product-level add-ons inside the v5 editor.
domReady( () => {
    addFilter(
        'dokan_product_editor_ui_variant',
        'dokan-pro/product-addon/variant',
        ( variants: Record< string, any > ) => {
            variants.product_addons = () => ( {
                Edit: ProductAddonsEdit,
                type: 'array',
            } );
            return variants;
        }
    );
} );
